/* Interactive steganography decision-tree map (/cheatsheet/map).
 *
 * The SVG is generated by scripts/gen_decision_tree.py and inlined by the map
 * template; each step carries a transparent `.ds-step` overlay with data-b/data-s
 * indices into the JSON model in #ds-data. This script adds:
 *   - hover / focus / tap tooltips (command, detail, copy, "Learn more" link),
 *   - fit / zoom / pan of the canvas,
 *   - PNG and PDF export of the whole tree.
 * It runs only on the map page (all lookups are null-guarded).
 */
(function initDecisionMap() {
  "use strict";

  const dataEl = document.getElementById("ds-data");
  const viewport = document.getElementById("ds-viewport");
  const canvas = document.getElementById("ds-canvas");
  const tooltip = document.getElementById("ds-tooltip");
  const svg = canvas && canvas.querySelector("svg");
  if (!dataEl || !viewport || !canvas || !tooltip || !svg) return;

  let model;
  try {
    model = JSON.parse(dataEl.textContent);
  } catch (err) {
    return;
  }

  const LANG_PREFIX = window.LANG_PREFIX || "";
  const t = (key) => (window.I18N && window.I18N[key]) || key;
  const box = svg.viewBox.baseVal;
  const NAT_W = box && box.width ? box.width : svg.width.baseVal.value;
  const NAT_H = box && box.height ? box.height : svg.height.baseVal.value;

  /* ---- Tooltip -------------------------------------------------------- */

  const escapeHtml = (s) =>
    String(s).replace(/[&<>"']/g, (c) => ({
      "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;",
    }[c]));

  let pinned = false;
  let hideTimer = null;

  const stepFor = (el) => {
    if (el.hasAttribute("data-root")) {
      return { title: model.root.title, detail: model.root.detail, full: "", href: "" };
    }
    const branch = model.branches[+el.dataset.b];
    if (!branch) return null;
    const step = branch.steps[+el.dataset.s];
    if (!step) return null;
    return {
      title: branch.label + " · " + step.n + ". " + step.cmd,
      detail: step.detail,
      full: step.full,
      href: step.href,
      color: branch.color,
    };
  };

  const fillTooltip = (info) => {
    let html = "";
    if (info.color) {
      html += '<div class="ds-tt-head" style="color:' + info.color + '">' +
        escapeHtml(info.title) + "</div>";
    } else {
      html += '<div class="ds-tt-head">' + escapeHtml(info.title) + "</div>";
    }
    if (info.full) {
      html += '<div class="ds-tt-cmd"><code>' + escapeHtml(info.full) + "</code>" +
        '<button type="button" class="ds-tt-copy" title="' + escapeHtml(t("Copy")) +
        '"><i class="fa fa-copy"></i></button></div>';
    }
    if (info.detail) {
      html += '<p class="ds-tt-detail">' + escapeHtml(info.detail) + "</p>";
    }
    if (info.href) {
      const external = /^https?:/.test(info.href);
      const href = external ? info.href : LANG_PREFIX + info.href;
      const attrs = external ? ' target="_blank" rel="noopener"' : "";
      html += '<a class="ds-tt-link" href="' + escapeHtml(href) + '"' + attrs + ">" +
        escapeHtml(t("Learn more")) + " →</a>";
    }
    tooltip.innerHTML = html;
    const copyBtn = tooltip.querySelector(".ds-tt-copy");
    if (copyBtn) {
      copyBtn.addEventListener("click", (ev) => {
        ev.stopPropagation();
        navigator.clipboard && navigator.clipboard.writeText(info.full).then(() => {
          copyBtn.innerHTML = '<i class="fa fa-check"></i>';
          setTimeout(() => { copyBtn.innerHTML = '<i class="fa fa-copy"></i>'; }, 1200);
        });
      });
    }
  };

  const positionTooltip = (target) => {
    const r = target.getBoundingClientRect();
    tooltip.hidden = false;
    const tw = tooltip.offsetWidth;
    const th = tooltip.offsetHeight;
    const margin = 10;
    let left = r.left + r.width / 2 - tw / 2;
    left = Math.max(margin, Math.min(left, window.innerWidth - tw - margin));
    let top = r.bottom + 8;
    if (top + th > window.innerHeight - margin) top = r.top - th - 8;
    if (top < margin) top = margin;
    tooltip.style.left = left + "px";
    tooltip.style.top = top + "px";
  };

  const showTooltip = (target) => {
    const info = stepFor(target);
    if (!info) return;
    clearTimeout(hideTimer);
    fillTooltip(info);
    positionTooltip(target);
    tooltip.classList.add("is-visible");
  };

  const hideTooltip = (force) => {
    if (pinned && !force) return;
    pinned = false;
    tooltip.classList.remove("is-visible");
    tooltip.hidden = true;
  };

  const scheduleHide = () => {
    clearTimeout(hideTimer);
    hideTimer = setTimeout(() => hideTooltip(false), 200);
  };

  canvas.addEventListener("pointerover", (e) => {
    const step = e.target.closest && e.target.closest(".ds-step");
    if (step && !pinned && e.pointerType === "mouse") showTooltip(step);
  });
  canvas.addEventListener("pointerout", (e) => {
    const step = e.target.closest && e.target.closest(".ds-step");
    if (step && !pinned && e.pointerType === "mouse") scheduleHide();
  });
  canvas.addEventListener("focusin", (e) => {
    const step = e.target.closest && e.target.closest(".ds-step");
    if (step) showTooltip(step);
  });
  canvas.addEventListener("focusout", () => scheduleHide());

  tooltip.addEventListener("pointerenter", () => clearTimeout(hideTimer));
  tooltip.addEventListener("pointerleave", () => scheduleHide());

  // Click / tap / Enter on a step pins the tooltip (so its link and copy button
  // stay reachable, and touch users get a tooltip at all).
  const togglePin = (step) => {
    if (pinned && tooltip.dataset.for === step.getAttribute("aria-label")) {
      hideTooltip(true);
    } else {
      pinned = false;
      showTooltip(step);
      pinned = true;
      tooltip.dataset.for = step.getAttribute("aria-label");
    }
  };

  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") hideTooltip(true);
    const step = e.target.closest && e.target.closest(".ds-step");
    if (step && (e.key === "Enter" || e.key === " ")) {
      e.preventDefault();
      togglePin(step);
    }
  });
  document.addEventListener("click", (e) => {
    if (tooltip.contains(e.target)) return;
    const step = e.target.closest && e.target.closest(".ds-step");
    if (step) {
      if (draggedRecently) return;
      togglePin(step);
    } else if (pinned) {
      hideTooltip(true);
    }
  });

  /* ---- Fit / zoom / pan ---------------------------------------------- */

  let scale = 1;
  let tx = 0;
  let ty = 0;
  const MIN_SCALE = 0.2;
  const MAX_SCALE = 8;

  const applyTransform = () => {
    canvas.style.transform =
      "translate(" + tx + "px," + ty + "px) scale(" + scale + ")";
  };

  const fit = () => {
    const vw = viewport.clientWidth;
    const vh = viewport.clientHeight;
    scale = Math.min(vw / NAT_W, vh / NAT_H) * 0.98;
    tx = (vw - NAT_W * scale) / 2;
    ty = (vh - NAT_H * scale) / 2;
    applyTransform();
  };

  const zoomAt = (factor, cx, cy) => {
    const next = Math.max(MIN_SCALE, Math.min(MAX_SCALE, scale * factor));
    const ratio = next / scale;
    // Keep the point under (cx, cy) fixed while scaling.
    tx = cx - (cx - tx) * ratio;
    ty = cy - (cy - ty) * ratio;
    scale = next;
    applyTransform();
  };

  const centerZoom = (factor) => {
    const rect = viewport.getBoundingClientRect();
    zoomAt(factor, rect.width / 2, rect.height / 2);
  };

  const btn = (id, fn) => {
    const el = document.getElementById(id);
    if (el) el.addEventListener("click", fn);
  };
  btn("ds-zoom-in", () => centerZoom(1.25));
  btn("ds-zoom-out", () => centerZoom(0.8));
  btn("ds-zoom-reset", () => fit());

  viewport.addEventListener(
    "wheel",
    (e) => {
      e.preventDefault();
      const rect = viewport.getBoundingClientRect();
      zoomAt(e.deltaY < 0 ? 1.12 : 0.89, e.clientX - rect.left, e.clientY - rect.top);
    },
    { passive: false }
  );

  // Drag to pan. A tiny movement is treated as a click (not a drag) so the
  // step-click handler still fires.
  let panning = false;
  let panStart = null;
  let draggedRecently = false;
  viewport.addEventListener("pointerdown", (e) => {
    if (e.button !== 0) return;
    panning = true;
    draggedRecently = false;
    panStart = { x: e.clientX, y: e.clientY, tx, ty };
    viewport.classList.add("is-grabbing");
  });
  window.addEventListener("pointermove", (e) => {
    if (!panning) return;
    const dx = e.clientX - panStart.x;
    const dy = e.clientY - panStart.y;
    if (Math.abs(dx) + Math.abs(dy) > 4) draggedRecently = true;
    tx = panStart.tx + dx;
    ty = panStart.ty + dy;
    applyTransform();
  });
  window.addEventListener("pointerup", () => {
    panning = false;
    viewport.classList.remove("is-grabbing");
    // Let the click handler read draggedRecently, then reset it.
    setTimeout(() => { draggedRecently = false; }, 0);
  });

  window.addEventListener("resize", fit);
  fit();
  canvas.classList.add("ds-ready");

  /* ---- Export -------------------------------------------------------- */

  const PANEL = "#0d1522";

  const serializeSvg = () => {
    const clone = svg.cloneNode(true);
    clone.removeAttribute("class");
    clone.setAttribute("width", NAT_W);
    clone.setAttribute("height", NAT_H);
    // Drop the interaction overlay; it is invisible but pointless in an export.
    const hits = clone.querySelector(".ds-hits");
    if (hits) hits.remove();
    return new XMLSerializer().serializeToString(clone);
  };

  const rasterize = (scaleUp) =>
    new Promise((resolve, reject) => {
      const xml = serializeSvg();
      const blob = new Blob([xml], { type: "image/svg+xml;charset=utf-8" });
      const url = URL.createObjectURL(blob);
      const img = new Image();
      img.onload = () => {
        const out = document.createElement("canvas");
        out.width = Math.round(NAT_W * scaleUp);
        out.height = Math.round(NAT_H * scaleUp);
        const ctx = out.getContext("2d");
        ctx.fillStyle = PANEL;
        ctx.fillRect(0, 0, out.width, out.height);
        ctx.drawImage(img, 0, 0, out.width, out.height);
        URL.revokeObjectURL(url);
        resolve(out);
      };
      img.onerror = () => {
        URL.revokeObjectURL(url);
        reject(new Error("svg render failed"));
      };
      img.src = url;
    });

  const triggerDownload = (href, name) => {
    const a = document.createElement("a");
    a.href = href;
    a.download = name;
    document.body.appendChild(a);
    a.click();
    a.remove();
  };

  const flashHint = (msg) => {
    const hint = document.querySelector(".ds-hint");
    if (!hint) return;
    const prev = hint.innerHTML;
    hint.textContent = msg;
    setTimeout(() => { hint.innerHTML = prev; }, 4000);
  };

  btn("ds-dl-png", () => {
    rasterize(2)
      .then((out) => out.toBlob((blob) => {
        triggerDownload(URL.createObjectURL(blob), "aperisolve-decision-tree.png");
      }, "image/png"))
      .catch(() => flashHint(t("Export failed. Please try again.")));
  });

  btn("ds-dl-pdf", () => {
    const jspdf = window.jspdf && window.jspdf.jsPDF;
    if (!jspdf) {
      flashHint(t("PDF export is unavailable (the PDF library failed to load)."));
      return;
    }
    rasterize(2)
      .then((out) => {
        const pdf = new jspdf({ orientation: "landscape", unit: "pt", format: [NAT_W, NAT_H] });
        pdf.addImage(out.toDataURL("image/png"), "PNG", 0, 0, NAT_W, NAT_H);
        pdf.save("aperisolve-decision-tree.pdf");
      })
      .catch(() => flashHint(t("Export failed. Please try again.")));
  });
})();
